#include<bits/stdc++.h>
using namespace std;
#define ll long long
const int N=100005;
int n,a[N],b[N];
struct node
{
	int x,y,num;
	bool operator<(const node other) const
	{
		return num>other.num;
	}
};
priority_queue<node> q;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	for(int i=1;i<=n;i++)
	{
		cin>>b[i];
	}
	b[n+1]=0x3f3f3f3f;
	for(int i=1;i<=n;i++)
	{
		q.push(node{i,1,a[i]+b[1]});
	}
	for(int i=1;i<=n;i++)
	{
		node t=q.top();
//		cout<<t.x<<" "<<t.y<<" "<<t.num<<"\n";
		q.pop();
		cout<<t.num<<" ";
		t.num-=b[t.y];
		t.num+=b[++t.y];
		q.push(t);
	}
	return 0;
}
